#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    vector<int> findRepeatingMissing(vector<int>& nums) {
        long long n = nums.size();
        long long total = n * (n + 1) / 2;
        long long total_sq = n * (n + 1) * (2 * n + 1) / 6;
        long long s = 0, s_sq = 0;
        for (int x : nums) {
            s += x;
            s_sq += 1LL * x * x;
        }
        long long diff = s - total;            // A - B
        long long sq_diff = s_sq - total_sq;    // A^2 - B^2 = (A-B)(A+B)
        long long sum_ab = sq_diff / diff;     // A + B
        long long A = (diff + sum_ab) / 2;
        long long B = A - diff;
        return {(int)A, (int)B};
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> nums(n);
    for (int i = 0; i < n; ++i) cin >> nums[i];
    Solution sol;
    vector<int> ans = sol.findRepeatingMissing(nums);
    cout << ans[0] << " " << ans[1] << "\n";
    return 0;
}
